1	// Increment 4 — Teams transcript ingestion.
2	//
3	// Triggered by the webhook (apps/web/app/api/teams/notifications) when Graph
4	// pushes a transcript notification. Fetches the WebVTT, turns each speaker turn
5	// into a `messages` row inside a channel that represents the call, and leaves
6	// them as extraction_status='pending' so the existing claim-extraction cron
7	// picks them up — NOTHING here writes to claims directly (candidate-before-claim).
8	//
9	// Design notes:
10	//   - Each utterance = one message with role='user', employeeId = the resolved
11	//     speaker (or null when we can't match the name). This preserves speaker
12	//     attribution + verbatim quotes for evidence, exactly like chat messages.
13	//   - Idempotent: re-running for the same transcript is a no-op (clientMessageId
14	//     `teams:<transcriptId>:<n>` is the dedupe key).
15	//
16	// Known v1 limitations (intentional, documented for follow-up):
17	//   - Speaker→employee match is by display-name (case-insensitive) against
18	//     employees.name. Teams VTT carries display names, not emails/AAD ids, so
19	//     unmatched speakers get a null employeeId. TODO: resolve via AAD id when
20	//     the decrypted resource exposes participant identities.
21	//   - Message createdAt is anchored to ingestion time + the cue offset (so all
22	//     cues cluster into a single extraction segment). TODO: anchor to the real
23	//     meeting start when available.
24	
25	import { task } from '@trigger.dev/sdk/v3';
26	import { eq, sql } from 'drizzle-orm';
27	import { createHash } from 'node:crypto';
28	import { getDirectDb } from '@oracle/db/client';
29	import {
30	  channels,
31	  channelParticipants,
32	  employees,
33	  employeeIdentities,
34	  jobRuns,
35	  messages,
36	} from '@oracle/db';
37	import { fetchTranscriptVtt, listDisplayNameToEmail } from '../lib/graph-transcripts';
38	
39	interface IngestionPayload {
40	  resourcePath?: string | null;
41	  transcriptContentUrl?: string | null;
42	  meetingId?: string | null;
43	  callId?: string | null;
44	  subscriptionId?: string | null;
45	}
46	
47	interface Cue {
48	  speaker: string | null;
49	  text: string;
50	  offsetMs: number;
51	}
52	
53	function vttTimeToMs(t: string): number {
54	  const p = t.trim().split(':').map((x) => Number.parseFloat(x) || 0);
55	  if (p.length === 3) {
56	    return Math.round(((p[0] ?? 0) * 3600 + (p[1] ?? 0) * 60 + (p[2] ?? 0)) * 1000);
57	  }
58	  if (p.length === 2) {
59	    return Math.round(((p[0] ?? 0) * 60 + (p[1] ?? 0)) * 1000);
60	  }
61	  return 0;
62	}
63	
64	/** Parse Teams WebVTT into cues. Handles `<v Speaker Name>text</v>` voice tags. */
65	export function parseVtt(vtt: string): Cue[] {
66	  const cues: Cue[] = [];
67	  const blocks = vtt.replace(/\r/g, '').split(/\n\n+/);
68	  for (const block of blocks) {
69	    const lines = block.split('\n').filter((l) => l.trim() !== '');
70	    const timingIdx = lines.findIndex((l) => l.includes('-->'));
71	    if (timingIdx === -1) continue;
72	    const timingLine = lines[timingIdx];
73	    if (!timingLine) continue;
74	    const offsetMs = vttTimeToMs(timingLine.split('-->')[0] ?? '');
75	
76	    let text = lines.slice(timingIdx + 1).join(' ').trim();
77	    let speaker: string | null = null;
78	    const voice = text.match(/<v\s+([^>]+)>([\s\S]*?)<\/v>/i);
79	    if (voice) {
80	      speaker = (voice[1] ?? '').trim();
81	      text = (voice[2] ?? '').trim();
82	    } else {
83	      text = text.replace(/<[^>]+>/g, '').trim();
84	    }
85	    if (text) cues.push({ speaker, text, offsetMs });
86	  }
87	  return cues;
88	}
89	
90	/** Merge consecutive cues from the same speaker into one fuller utterance. */
91	function mergeBySpeaker(cues: Cue[]): Cue[] {
92	  const out: Cue[] = [];
93	  for (const c of cues) {
94	    const last = out[out.length - 1];
95	    if (last && last.speaker === c.speaker) {
96	      last.text = `${last.text} ${c.text}`.trim();
97	    } else {
98	      out.push({ ...c });
99	    }
100	  }
101	  return out;
102	}
103	
104	/** Stable id for this transcript, used for idempotency + provenance. */
105	function deriveTranscriptId(p: IngestionPayload): string {
106	  const src = p.transcriptContentUrl || p.resourcePath || '';
107	  const m = src.match(/transcripts[('/]+([^')/]+)/i);
108	  if (m && m[1]) return m[1];
109	  return createHash('sha256')
110	    .update(src + (p.meetingId ?? '') + (p.callId ?? ''))
111	    .digest('hex')
112	    .slice(0, 32);
113	}
114	
115	export const teamsTranscriptIngestionTask = task({
116	  id: 'teams-transcript-ingestion',
117	  maxDuration: 60 * 5,
118	  run: async (payload: IngestionPayload, { ctx }) => {
119	    const db = getDirectDb();
120	    const [jobRun] = await db
121	      .insert(jobRuns)
122	      .values({
123	        triggerRunId: ctx.run.id,
124	        jobType: 'teams-transcript-ingestion',
125	        status: 'running',
126	        startedAt: new Date(),
127	        inputJson: payload,
128	      })
129	      .returning({ id: jobRuns.id });
130	    if (!jobRun) throw new Error('[teams-transcript-ingestion] failed to insert job_runs row');
131	
132	    try {
133	      const transcriptId = deriveTranscriptId(payload);
134	
135	      // Idempotency: bail if we've already ingested this transcript.
136	      const already = await db
137	        .select({ id: messages.id })
138	        .from(messages)
139	        .where(sql`${messages.clientMessageId} like ${`teams:${transcriptId}:%`}`)
140	        .limit(1);
141	      if (already.length > 0) {
142	        const out = { skipped: true, reason: 'already ingested', transcriptId };
143	        await db
144	          .update(jobRuns)
145	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
146	          .where(eq(jobRuns.id, jobRun.id));
147	        return { ok: true, ...out };
148	      }
149	
150	      const vtt = await fetchTranscriptVtt(
151	        payload.transcriptContentUrl ?? null,
152	        payload.resourcePath ?? null,
153	      );
154	      const cues = mergeBySpeaker(parseVtt(vtt));
155	
156	      if (cues.length === 0) {
157	        const out = { transcriptId, messages: 0, reason: 'empty transcript' };
158	        await db
159	          .update(jobRuns)
160	          .set({ status: 'complete', finishedAt: new Date(), outputJson: out })
