30	
31	type ReviewStatus = 'approved' | 'rejected';
32	
33	export type AssignClaimQuestionState = {
34	  status: 'idle' | 'success' | 'error';
35	  message: string | null;
36	};
37	
38	function intFromForm(formData: FormData, key: string, fallback: number): number {
39	  const raw = String(formData.get(key) ?? '').trim();
40	  const parsed = Number.parseInt(raw, 10);
41	  if (!Number.isFinite(parsed)) return fallback;
42	  return Math.max(1, Math.min(10, parsed));
43	}
44	
45	function buildAutoRevisionNote(input: {
46	  beforeSummary: string;
47	  afterSummary: string;
48	  beforeClaimType: string;
49	  afterClaimType: string;
50	  beforeImpact: number;
51	  afterImpact: number;
52	  beforeConfidence: number;
53	  afterConfidence: number;
54	  beforeDomains: string[];
55	  afterDomains: string[];
56	}): string {
57	  const changes: string[] = [];
58	  if (input.beforeSummary !== input.afterSummary) {
59	    changes.push(`summary changed from "${input.beforeSummary}" to "${input.afterSummary}"`);
60	  }
61	  if (input.beforeClaimType !== input.afterClaimType) {
62	    changes.push(`claim type changed from ${input.beforeClaimType} to ${input.afterClaimType}`);
63	  }
64	  if (input.beforeImpact !== input.afterImpact) {
65	    changes.push(`impact changed from ${input.beforeImpact} to ${input.afterImpact}`);
66	  }
67	  if (input.beforeConfidence !== input.afterConfidence) {
68	    changes.push(`confidence changed from ${input.beforeConfidence} to ${input.afterConfidence}`);
69	  }
70	  const beforeDomains = input.beforeDomains.join(', ') || '(none)';
71	  const afterDomains = input.afterDomains.join(', ') || '(none)';
72	  if (beforeDomains !== afterDomains) {
73	    changes.push(`domains changed from ${beforeDomains} to ${afterDomains}`);
74	  }
75	  return changes.length > 0
76	    ? `Reviewer revised the AI claim: ${changes.join('; ')}.`
77	    : 'Reviewer resubmitted the claim without changing the reviewed fields.';
78	}
79	
80	async function recalculateClaimDomainIds(input: {
81	  summary: string;
82	  claimType: string;
83	  fallbackDomainIds: string[];
84	}): Promise<{ domainIds: string[]; method: 'retrieval_plan_heuristic' | 'fallback_original_domains' }> {
85	  const db = getDirectDb();
86	  const plan = buildRetrievalPlanFromQuery(`${input.claimType}\n${input.summary}`);
87	  const inferredDomainIds = plan.topDomainHints;
88	  if (inferredDomainIds.length === 0) {
89	    return { domainIds: input.fallbackDomainIds, method: 'fallback_original_domains' };
90	  }
91	
92	  const validDomains = await db
93	    .select({ id: knowledgeTopDomains.id })
94	    .from(knowledgeTopDomains)
95	    .where(inArray(knowledgeTopDomains.id, inferredDomainIds));
96	  const validDomainIds = inferredDomainIds.filter((id) =>
97	    validDomains.some((domain) => domain.id === id),
98	  );
99	
100	  return validDomainIds.length > 0
101	    ? { domainIds: validDomainIds, method: 'retrieval_plan_heuristic' }
102	    : { domainIds: input.fallbackDomainIds, method: 'fallback_original_domains' };
103	}
104	
105	async function canReviewClaim(employeeId: string, isAdmin: boolean, claimId: string): Promise<boolean> {
106	  if (isAdmin) return true;
107	  const db = getDirectDb();
108	  const result = await db.execute(sql`
109	    SELECT EXISTS (
110	      SELECT 1
111	      FROM gaps g
112	      WHERE g.gap_type = 'claim_review_question'
113	        AND g.target_employee_id = ${employeeId}::uuid
114	        AND g.status IN ('open', 'queued', 'asked')
115	        AND g.related_claim_ids ? ${claimId}
116	    ) AS allowed
117	  `);
118	  const row = [...result][0] as { allowed?: boolean } | undefined;
119	  return row?.allowed === true;
120	}
121	
122	async function requireClaimReviewer(claimId: string) {
123	  const me = await requireEmployee();
124	  const allowed = await canReviewClaim(me.id, me.isAdmin, claimId);
125	  if (!allowed) {
126	    throw new Error('You do not have permission to review this claim.');
127	  }
128	  return me;
129	}
130	
131	async function claimSnapshot(claimId: string) {
132	  const db = getDirectDb();
133	  const [claim] = await db.select().from(claims).where(eq(claims.id, claimId)).limit(1);
134	  if (!claim) throw new Error('Claim not found.');
135	
136	  const domains = await db
137	    .select({ topDomainId: claimTopDomains.topDomainId })
138	    .from(claimTopDomains)
139	    .where(eq(claimTopDomains.claimId, claimId));
140	
141	  return {
142	    claim,
143	    topDomainIds: domains.map((d) => d.topDomainId),
144	  };
145	}
146	
147	function refreshClaimPages() {
148	  revalidatePath('/admin/claims');
149	  revalidatePath('/claims');
150	  revalidatePath('/admin/gaps');
151	}
152	
153	export async function updateClaimStatus(formData: FormData) {
154	  const id = String(formData.get('id') ?? '');
155	  const status = String(formData.get('status') ?? '') as ReviewStatus;
156	  if (!id || !['approved', 'rejected'].includes(status)) return;
157	
158	  const me = await requireClaimReviewer(id);
159	  const before = await claimSnapshot(id);
160	  const db = getDirectDb();
161	
162	  await db.transaction(async (tx) => {
163	    await tx.update(claims).set({ status }).where(eq(claims.id, id));
164	    await tx.insert(claimReviewEvents).values({
165	      claimId: id,
166	      action: status === 'approved' ? 'approve' : 'reject',
167	      reviewedByEmployeeId: me.id,
168	      reviewerNote: String(formData.get('reviewerNote') ?? '').trim() || null,
169	      beforeState: before,
170	      afterState: {
171	        claim: { ...before.claim, status },
172	        topDomainIds: before.topDomainIds,
173	      },
174	    });
175	  });
176	
177	  refreshClaimPages();
178	}
179	
180	export async function reviseClaim(formData: FormData) {
181	  const id = String(formData.get('id') ?? '');
182	  const summary = String(formData.get('summary') ?? '').trim();
183	  const claimType = String(formData.get('claimType') ?? '').trim();
184	  const reviewerNoteInput = String(formData.get('reviewerNote') ?? '').trim();
185	  if (!id || !summary || !claimType) return;
186	
187	  const me = await requireClaimReviewer(id);
188	  const before = await claimSnapshot(id);
189	  if (!['pending_review', 'approved'].includes(before.claim.status)) {
190	    throw new Error('Only pending or approved claims can be revised.');
191	  }
192	  const db = getDirectDb();
193	  const impactScore = intFromForm(formData, 'impactScore', before.claim.impactScore);
194	  const confidenceScore = intFromForm(formData, 'confidenceScore', before.claim.confidenceScore);
195	  const domainRecalculation = await recalculateClaimDomainIds({
196	    summary,
197	    claimType,
198	    fallbackDomainIds: before.topDomainIds,
199	  });
200	  const validDomainIds = domainRecalculation.domainIds;
201	  if (validDomainIds.length === 0) {
202	    throw new Error('The system could not infer a knowledge domain for this revised claim.');
203	  }
204	  const reviewerNote =
205	    reviewerNoteInput ||
206	    buildAutoRevisionNote({
207	      beforeSummary: before.claim.summary,
208	      afterSummary: summary,
209	      beforeClaimType: before.claim.claimType,
210	      afterClaimType: claimType,
211	      beforeImpact: before.claim.impactScore,
212	      afterImpact: impactScore,
213	      beforeConfidence: before.claim.confidenceScore,
214	      afterConfidence: confidenceScore,
215	      beforeDomains: before.topDomainIds,
216	      afterDomains: validDomainIds,
217	    });
218	
219	  await db.transaction(async (tx) => {
220	    const [replacement] = await tx
221	      .insert(claims)
222	      .values({
223	        claimType,
224	        summary,
225	        impactScore,
226	        confidenceScore,
227	        status: 'pending_review',
228	      })
229	      .returning({ id: claims.id });
230	
231	    if (!replacement) throw new Error('Replacement claim insert returned no row.');
232	    const replacementClaimId = replacement.id;
233	
234	    await tx.insert(claimTopDomains).values(
235	      validDomainIds.map((topDomainId) => ({
236	          claimId: replacementClaimId,
237	          topDomainId,
238	          assignmentConfidence: '1',
239	          assignmentReason: 'manual',
240	      })),
241	    );
242	
243	    const entities = await tx.select().from(claimEntities).where(eq(claimEntities.claimId, id));
244	    if (entities.length > 0) {
245	      await tx
246	        .insert(claimEntities)
247	        .values(entities.map((e) => ({ claimId: replacementClaimId, entityId: e.entityId })))
248	        .onConflictDoNothing();
249	    }
250	
251	    const [metadata] = await tx.select().from(claimMetadata).where(eq(claimMetadata.claimId, id)).limit(1);
252	    if (metadata) {
253	      await tx.insert(claimMetadata).values({
254	        claimId: replacementClaimId,
255	        processStage: metadata.processStage,
256	        department: metadata.department,
257	        geography: metadata.geography,
258	        documentClass: metadata.documentClass,
259	        effectiveFrom: metadata.effectiveFrom,
260	        effectiveUntil: metadata.effectiveUntil,
261	      });
262	    }
263	
264	    const evidence = await tx.select().from(claimEvidence).where(eq(claimEvidence.claimId, id));
265	    if (evidence.length > 0) {
266	      await tx.insert(claimEvidence).values(
267	        evidence.map((e) => ({
268	          claimId: replacementClaimId,
269	          sourceType: e.sourceType,
270	          sourceMessageId: e.sourceMessageId,
271	          sourceDocumentChunkId: e.sourceDocumentChunkId,
272	          sourceExternalRecordId: e.sourceExternalRecordId,
273	          assertedByEmployeeId: e.assertedByEmployeeId,
274	          uploadedByEmployeeId: e.uploadedByEmployeeId,
275	          createdByEmployeeId: e.createdByEmployeeId,
276	          exactQuote: e.exactQuote,
277	          charStart: e.charStart,
278	          charEnd: e.charEnd,
279	          pageNumber: e.pageNumber,
280	          confidence: e.confidence,
281	        })),
282	      );
283	    }
284	
285	    await tx.update(claims).set({ status: 'superseded' }).where(eq(claims.id, id));
286	
287	    await tx
288	      .insert(claimMetadata)
289	      .values({
290	        claimId: id,
291	        supersededByClaimId: replacementClaimId,
292	        updatedAt: new Date(),
293	      })
294	      .onConflictDoUpdate({
295	        target: claimMetadata.claimId,
296	        set: {
297	          supersededByClaimId: replacementClaimId,
298	          updatedAt: new Date(),
299	        },
300	      });
301	
302	    await tx.insert(claimReviewEvents).values({
303	      claimId: id,
304	      replacementClaimId,
305	      action: 'revise',
306	      reviewedByEmployeeId: me.id,
307	      reviewerNote: reviewerNote || null,
308	      beforeState: before,
309	      afterState: {
310	        claim: {
311	          id: replacementClaimId,
312	          claimType,
313	          summary,
314	          impactScore,
315	          confidenceScore,
316	          status: 'pending_review',
317	        },
318	        topDomainIds: validDomainIds,
319	      },
320	      aiComparisonJson: {
321	        originalSummary: before.claim.summary,
322	        revisedSummary: summary,
323	        originalTopDomainIds: before.topDomainIds,
324	        revisedTopDomainIds: validDomainIds,
325	        domainRecalculationMethod: domainRecalculation.method,
326	        reviewerNoteWasGenerated: !reviewerNoteInput,
327	      },
328	    });
329	  });
330	
331	  refreshClaimPages();
332	}
333	
334	async function assignClaimQuestionImpl(formData: FormData): Promise<{ targetName: string }> {
335	  const claimId = String(formData.get('claimId') ?? '').trim();
336	  const targetEmployeeIds = formData
337	    .getAll('targetEmployeeIds')
338	    .map((value) => String(value).trim())
339	    .filter(Boolean);
340	  const targetGroupIds = formData
341	    .getAll('targetGroupIds')
342	    .map((value) => String(value).trim())
343	    .filter(Boolean);
344	  const questionInput = String(formData.get('question') ?? '').trim();
345	  return assignClaimQuestionCore({ claimId, targetEmployeeIds, targetGroupIds, questionInput });
346	}
347	
348	/**
349	 * Core "ask someone to verify/evaluate this claim" logic, keyed to a single
350	 * claim. Extracted so the per-row form (assignClaimQuestionImpl) and the bulk
351	 * action (assignClaimQuestionBulkWithState) share the exact same recipient
352	 * resolution, dedup-against-existing-assignments, per-recipient zh-CN auto
353	 * translation, gap insertion, and audit trail. `questionInput` empty → each
354	 * claim falls back to its own summary-based default question.
355	 */
356	async function assignClaimQuestionCore({
357	  claimId,
358	  targetEmployeeIds,
359	  targetGroupIds,
360	  questionInput,
361	}: {
362	  claimId: string;
363	  targetEmployeeIds: string[];
364	  targetGroupIds: string[];
365	  questionInput: string;
366	}): Promise<{ targetName: string }> {
367	  if (!claimId) throw new Error('Missing claim.');
368	  if (targetEmployeeIds.length === 0 && targetGroupIds.length === 0) {
369	    throw new Error('Choose at least one person or group before assigning the question.');
370	  }
371	
372	  const me = await requireClaimReviewer(claimId);
373	  const before = await claimSnapshot(claimId);
374	  const db = getDirectDb();
375	
376	  const directTargets =
377	    targetEmployeeIds.length > 0
378	      ? await db
379	          .select({ id: employees.id, name: employees.name, locale: employees.locale })
380	          .from(employees)
381	          .where(and(inArray(employees.id, targetEmployeeIds), isNull(employees.disabledAt)))
382	      : [];
383	
384	  const groupTargets =
385	    targetGroupIds.length > 0
386	      ? await db
387	          .select({
388	            employeeId: employees.id,
389	            employeeName: employees.name,
390	            employeeLocale: employees.locale,
391	            groupId: claimReviewGroups.id,
392	            groupName: claimReviewGroups.name,
393	          })
394	          .from(claimReviewGroupMembers)
395	          .innerJoin(
396	            claimReviewGroups,
397	            eq(claimReviewGroups.id, claimReviewGroupMembers.groupId),
398	          )
399	          .innerJoin(employees, eq(employees.id, claimReviewGroupMembers.employeeId))
400	          .where(
401	            and(
402	              inArray(claimReviewGroupMembers.groupId, targetGroupIds),
403	              isNull(claimReviewGroups.archivedAt),
404	              isNull(employees.disabledAt),
405	            ),
406	          )
407	      : [];
408	
409	  const recipientsById = new Map<
410	    string,
411	    { id: string; name: string; locale: string; groupNames: string[] }
412	  >();
413	  for (const target of directTargets) {
414	    recipientsById.set(target.id, {
415	      id: target.id,
416	      name: target.name,
417	      locale: target.locale,
418	      groupNames: [],
419	    });
420	  }
421	  for (const target of groupTargets) {
422	    const existing = recipientsById.get(target.employeeId);
423	    if (existing) {
424	      if (!existing.groupNames.includes(target.groupName)) {
425	        existing.groupNames.push(target.groupName);
426	      }
427	    } else {
428	      recipientsById.set(target.employeeId, {
429	        id: target.employeeId,
430	        name: target.employeeName,
431	        locale: target.employeeLocale,
432	        groupNames: [target.groupName],
433	      });
434	    }
435	  }
436	
437	  const recipients = [...recipientsById.values()].sort((a, b) => a.name.localeCompare(b.name));
438	  if (recipients.length === 0) {
439	    throw new Error('No active employees were found for the selected people or groups.');
440	  }
441	
442	  const question =
443	    questionInput ||
444	    `Can you help correct or confirm this claim?\n\n${before.claim.summary}`;
445	
446	  const existingAssignments = await db.execute(sql`
447	    SELECT target_employee_id
448	    FROM gaps
449	    WHERE gap_type = 'claim_review_question'
450	      AND status IN ('open', 'queued', 'asked')
451	      AND related_claim_ids ? ${claimId}
452	      AND target_employee_id IN (
453	        SELECT value::uuid
454	        FROM jsonb_array_elements_text(${JSON.stringify(recipients.map((recipient) => recipient.id))}::jsonb)
455	      )
456	  `);
457	  const alreadyAssignedIds = new Set(
458	    ([...existingAssignments] as Array<{ target_employee_id: string | null }>)
459	      .map((row) => row.target_employee_id)
460	      .filter((id): id is string => Boolean(id)),
461	  );
462	  const newRecipients = recipients.filter((recipient) => !alreadyAssignedIds.has(recipient.id));
463	
464	  if (newRecipients.length === 0) {
465	    throw new Error('All selected recipients already have an open assignment for this claim.');
466	  }
467	
468	  // Bilingual (china_imp.md): each recipient is asked in their own language, so a
469	  // China-team (zh-CN) recipient — direct or via a group containing them — gets a
470	  // Chinese question while everyone else gets the original English. Only zh-CN
471	  // recipients trigger a translation; failure falls back to the original text.
472	  const needsChinese = newRecipients.some((recipient) => recipient.locale === 'zh-CN');
473	  let zhQuestion = question;
474	  if (needsChinese) {
475	    try {
476	      zhQuestion = await translateReviewQuestionToChinese(db, question);
477	    } catch (err) {
478	      console.warn('[claims] zh-CN question translation failed; using original text', err);
479	      zhQuestion = question;
480	    }
481	  }
482	  const zhWhyItMatters =
483	    '复核请求：审核人员标记此条目，需相关同事确认或更正后方可批准。';
484	  const enWhyItMatters =
485	    'A reviewer flagged this claim as needing subject-matter input before it can be approved.';
486	
487	  await db.transaction(async (tx) => {
488	    const insertedGaps = await tx
489	      .insert(gaps)
490	      .values(newRecipients.map((recipient) => ({
491	        gapType: 'claim_review_question',
492	        relatedClaimIds: [claimId],
493	        questionToAsk: recipient.locale === 'zh-CN' ? zhQuestion : question,
494	        whyItMatters: recipient.locale === 'zh-CN' ? zhWhyItMatters : enWhyItMatters,
495	        targetEmployeeId: recipient.id,
496	        priority: 'medium' as const,
497	        status: 'open' as const,
498	      })))
499	      .returning({ id: gaps.id });
500	
501	    await tx.insert(claimReviewEvents).values({
502	      claimId,
503	      action: 'assign_question',
504	      reviewedByEmployeeId: me.id,
505	      reviewerNote: `Assigned follow-up question to ${newRecipients
506	        .map((recipient) => recipient.name)
507	        .join(', ')}.`,
508	      beforeState: before,
509	      afterState: {
510	        assignedGapIds: insertedGaps.map((gap) => gap.id),
511	        targetEmployeeIds: newRecipients.map((recipient) => recipient.id),
512	        targetGroupIds,
513	        skippedAlreadyAssignedEmployeeIds: [...alreadyAssignedIds],
514	        questionToAsk: question,
515	      },
516	    });
517	  });
518	
519	  refreshClaimPages();
520	  const skippedCount = alreadyAssignedIds.size;
521	  const targetName =
522	    newRecipients.length === 1
523	      ? newRecipients[0]!.name
524	      : `${newRecipients.length} people${skippedCount > 0 ? ` (${skippedCount} already assigned)` : ''}`;
525	  return { targetName };
526	}
527	
528	export async function assignClaimQuestion(formData: FormData) {
529	  await assignClaimQuestionImpl(formData);
530	}
531	
532	export async function assignClaimQuestionWithState(
533	  _previousState: AssignClaimQuestionState,
534	  formData: FormData,
535	): Promise<AssignClaimQuestionState> {
536	  try {
537	    const result = await assignClaimQuestionImpl(formData);
538	    return {
539	      status: 'success',
540	      message: `Question assigned to ${result.targetName}.`,
541	    };
542	  } catch (error) {
543	    return {
544	      status: 'error',
545	      message: error instanceof Error ? error.message : 'The question could not be assigned.',
546	    };
547	  }
548	}
549	
550	/**
551	 * Bulk "ask selected to evaluate" — the reviewer ticks several (typically
552	 * pending_review) claims, picks one shared set of people/groups, and each claim
553	 * is routed to those recipients for evaluation. Each claim reuses
554	 * assignClaimQuestionCore with an empty question so it gets its own
555	 * summary-based default; zh-CN recipients are asked in Chinese automatically.
556	 *
557	 * Per-claim failures (e.g. every chosen recipient already has an open
558	 * assignment for that claim) are non-fatal and reported as a skipped count, so
559	 * one already-assigned claim doesn't abort the whole batch.
560	 */
561	export async function assignClaimQuestionBulkWithState(
562	  _previousState: AssignClaimQuestionState,
563	  formData: FormData,
564	): Promise<AssignClaimQuestionState> {
565	  const claimIds = [
566	    ...new Set(
567	      formData.getAll('claimId').map((value) => String(value).trim()).filter(Boolean),
568	    ),
569	  ];
570	  const targetEmployeeIds = formData
571	    .getAll('targetEmployeeIds')
572	    .map((value) => String(value).trim())
573	    .filter(Boolean);
574	  const targetGroupIds = formData
575	    .getAll('targetGroupIds')
576	    .map((value) => String(value).trim())
577	    .filter(Boolean);
578	
579	  if (claimIds.length === 0) {
580	    return { status: 'error', message: 'Tick at least one claim first.' };
581	  }
582	  if (targetEmployeeIds.length === 0 && targetGroupIds.length === 0) {
583	    return { status: 'error', message: 'Choose at least one person or group.' };
584	  }
585	
586	  let sent = 0;
587	  const failures: string[] = [];
588	  for (const claimId of claimIds) {
589	    try {
590	      await assignClaimQuestionCore({
591	        claimId,
592	        targetEmployeeIds,
593	        targetGroupIds,
594	        questionInput: '',
595	      });
596	      sent += 1;
597	    } catch (error) {
598	      failures.push(error instanceof Error ? error.message : String(error));
599	    }
600	  }
601	
602	  if (sent === 0) {
603	    return {
604	      status: 'error',
605	      message: failures[0] ?? 'Nothing was sent.',
606	    };
607	  }
608	  const skipped = failures.length;
609	  return {
610	    status: 'success',
611	    message: `Sent ${sent} claim${sent === 1 ? '' : 's'} for evaluation${
612	      skipped > 0 ? ` (${skipped} skipped — already assigned or ineligible)` : ''
613	    }.`,
614	  };
615	}
616	
617	// ---------------------------------------------------------------------------
618	// China bilingual claim layer (china_imp.md)
619	// ---------------------------------------------------------------------------
620	
621	/**
622	 * Translate a claim-review question into Simplified Chinese via the admin-chosen
623	 * translation model (`default_translation_route`), falling back to the shipped
624	 * default route when unset. Used so a `claim_review_question` directed at a
625	 * China-team (`zh-CN`) recipient is asked in Chinese. All inference goes through
626	 * OracleAIClient.
627	 */
628	async function translateReviewQuestionToChinese(
629	  db: ReturnType<typeof getDirectDb>,
630	  question: string,
631	): Promise<string> {
632	  const route =
633	    (await resolveAuxiliaryRouteFromSettings(db, 'translation')) ??
634	    getOracleRoute(DEFAULT_TRANSLATION_ROUTE_ID);
635	  if (!route) return question;
636	
637	  const client = new OracleAIClient({ adapters: buildStandardAdapters(), fallbackOnError: true });
638	  const result = await client.runText({
639	    taskType: 'claim_translation',
640	    routeId: route.routeId,
641	    promptVersion: 'claim-review-question-zh-v1',
642	    blocks: [
643	      makeBlock({
644	        id: 'review-question-translate-system',
645	        label: 'Translate review question to Chinese',
646	        kind: 'stable_system',
647	        content:
648	          'Translate the user message into Simplified Chinese (简体中文). Output ONLY the translation — no preamble, no quotes. Preserve meaning, proper nouns, numbers, and codes.',
649	        reasonIncluded: 'Translate a claim-review question for a China-team recipient',
650	      }),
651	      makeBlock({
652	        id: 'review-question-translate-input',
653	        label: 'Question text',
654	        kind: 'dynamic_input',
655	        content: question,
656	        reasonIncluded: 'The English question to translate',
657	      }),
658	    ],
659	  });
660	  return result.text.trim() || question;
661	}
662	
663	/**
664	 * Bilingual claim layer: translate the SELECTED approved claims into the other
665	 * supported language(s) for the China team. Opt-in per claim (admin selects
666	 * them); the `claim-translation` worker is idempotent and skips non-approved
667	 * claims. Untranslated claims are still visible to China readers, in English.
668	 */
669	export async function translateClaimsForChina(formData: FormData) {
670	  await requireAdmin();
671	
672	  const ids = Array.from(
673	    new Set(
674	      formData
675	        .getAll('claimId')
676	        .filter((v): v is string => typeof v === 'string' && v.length > 0),
677	    ),
678	  );
679	  if (ids.length === 0) return;
680	
681	  for (const id of ids) {
682	    await triggerTask('claim-translation', { claimId: id });
683	  }
684	
685	  refreshClaimPages();
686	}
