// One-off: apply the two hand-written idempotent transcript-gate SQL files to
// the dev DB in .env.local (DIRECT_URL). Verification only — delete after.
import { config as loadEnv } from 'dotenv';
import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import postgres from 'postgres';

const root = resolve(process.cwd(), '..', '..');
loadEnv({ path: resolve(root, '.env.local') });
loadEnv({ path: resolve(root, '.env') });

const url = process.env.DIRECT_URL ?? process.env.DATABASE_URL;
if (!url) throw new Error('no DIRECT_URL/DATABASE_URL');
const host = new URL(url).host;
console.log('target host:', host);

const sql = postgres(url, { max: 1, prepare: true });
try {
  for (const f of [
    'migrations/sql/75_extraction_status_awaiting_approval.sql',
    'migrations/sql/76_transcript_approval.sql',
  ]) {
    const text = await readFile(resolve(process.cwd(), f), 'utf8');
    await sql.unsafe(text);
    console.log('applied:', f);
  }
  const cols = await sql`
    SELECT column_name FROM information_schema.columns
    WHERE table_name = 'raw_transcripts' ORDER BY column_name`;
  console.log('raw_transcripts columns:', cols.map((c) => c.column_name).join(', '));
  const enums = await sql`
    SELECT enumlabel FROM pg_enum e
