// READ-ONLY verification that the transcript-gate schema landed on prod.
// No writes/DDL. Connection string passed via VERIFY_URL env. Delete after.
import postgres from 'postgres';

const url = process.env.VERIFY_URL;
if (!url) throw new Error('no VERIFY_URL');
const sql = postgres(url, { max: 1, prepare: true });
try {
  console.log('host:', new URL(url).host);

  const enums = await sql`
    SELECT enumlabel FROM pg_enum e
    JOIN pg_type t ON t.oid = e.enumtypid
    WHERE t.typname = 'extraction_status' ORDER BY e.enumsortorder`;
  console.log('extraction_status values:', enums.map((r) => r.enumlabel).join(', '));

  const cols = await sql`
    SELECT column_name, data_type, column_default
    FROM information_schema.columns
    WHERE table_name = 'raw_transcripts'
      AND column_name IN ('approval_status','reviewed_by_employee_id','reviewed_at','review_note')
    ORDER BY column_name`;
  console.log('raw_transcripts approval columns:');
  for (const c of cols) console.log('  ', c.column_name, '|', c.data_type, '| default:', c.column_default ?? '(none)');

  const chk = await sql`
    SELECT conname FROM pg_constraint
    WHERE conname = 'raw_transcripts_approval_status_check'`;
  console.log('check constraint present:', chk.length > 0);

  const dist = await sql`
    SELECT approval_status, count(*)::int AS n
    FROM raw_transcripts GROUP BY approval_status ORDER BY approval_status`;
  console.log('raw_transcripts approval_status distribution:',
    dist.length ? dist.map((r) => `${r.approval_status}=${r.n}`).join(', ') : '(no transcript rows yet)');
} finally {
  await sql.end({ timeout: 5 });
}

