// READ-ONLY: check for recent Teams transcript ingestion in whichever DB the
// CHECK_URL points at. No writes. Delete after.
import postgres from 'postgres';
const url = process.env.CHECK_URL;
if (!url) throw new Error('no CHECK_URL');
const sql = postgres(url, { max: 1, prepare: true });
try {
  console.log('host:', new URL(url).host);
  const rt = await sql`SELECT count(*)::int AS n, max(created_at) AS latest FROM raw_transcripts`;
  console.log('raw_transcripts:', rt[0].n, 'rows; latest:', rt[0].latest ?? '(none)');
  const tmsg = await sql`
    SELECT count(*)::int AS n, max(created_at) AS latest
    FROM messages WHERE metadata_json->>'source' = 'teams_transcript'`;
  console.log('teams_transcript messages:', tmsg[0].n, 'rows; latest:', tmsg[0].latest ?? '(none)');
  const ch = await sql`
    SELECT count(*)::int AS n, max(created_at) AS latest
    FROM channels WHERE name LIKE 'Teams call %'`;
  console.log('Teams-call channels:', ch[0].n, 'rows; latest:', ch[0].latest ?? '(none)');
  const jr = await sql`
    SELECT status, count(*)::int AS n, max(started_at) AS latest
    FROM job_runs WHERE job_type = 'teams-transcript-ingestion'
    GROUP BY status ORDER BY status`;
  console.log('teams-transcript-ingestion job_runs:',
    jr.length ? jr.map((r) => `${r.status}=${r.n} (latest ${r.latest})`).join('; ') : '(none)');
} finally {
  await sql.end({ timeout: 5 });
}

