1	// Self-contained Microsoft Graph helper for the Teams transcript workers.
2	//
3	// This lives in apps/workers (a separate Trigger.dev process from apps/web), so
4	// it intentionally re-implements the small app-only token + subscription
5	// surface rather than importing apps/web/lib/microsoft-graph.ts (cross-app
6	// imports aren't allowed). If this and the web copy drift, the web one
7	// (apps/web/lib/microsoft-graph.ts) is the reference.
8	//
9	// Required env (set in the Trigger.dev project, NOT just Vercel):
10	//   AZURE_TENANT_ID, AZURE_GRAPH_CLIENT_ID, AZURE_GRAPH_CLIENT_SECRET
11	//   TEAMS_NOTIFICATION_URL          (https://oracle.designflow.app/api/teams/notifications)
12	//   TEAMS_NOTIFICATION_PUBLIC_CERT  (base64 DER of the public cert)
13	//   TEAMS_NOTIFICATION_CERT_ID      (matches the webhook's cert id)
14	//   TEAMS_WEBHOOK_CLIENT_STATE      (shared secret; same value as the webhook)
15	
16	const GRAPH_BETA = 'https://graph.microsoft.com/beta';
17	const GRAPH_V1 = 'https://graph.microsoft.com/v1.0';
18	// Ad-hoc ("Meet Now") transcripts are only reachable via this subscription, and
19	// only on the beta endpoint (v1.0 rejects it).
20	const ADHOC_RESOURCE = 'communications/adhocCalls/getAllTranscripts';
21	
22	interface GraphConfig {
23	  tenantId: string;
24	  clientId: string;
25	  clientSecret: string;
26	}
27	
28	function getConfigOrNull(): GraphConfig | null {
29	  const tenantId = process.env.AZURE_TENANT_ID;
30	  const clientId = process.env.AZURE_GRAPH_CLIENT_ID;
31	  const clientSecret = process.env.AZURE_GRAPH_CLIENT_SECRET;
32	  if (!tenantId || !clientId || !clientSecret) return null;
33	  return { tenantId, clientId, clientSecret };
34	}
35	
36	let cachedToken: { token: string; refreshAt: number } | null = null;
37	
38	async function getToken(cfg: GraphConfig): Promise<string> {
39	  if (cachedToken && cachedToken.refreshAt > Date.now()) return cachedToken.token;
40	  const body = new URLSearchParams({
41	    client_id: cfg.clientId,
42	    client_secret: cfg.clientSecret,
43	    scope: 'https://graph.microsoft.com/.default',
44	    grant_type: 'client_credentials',
45	  });
46	  const res = await fetch(
47	    `https://login.microsoftonline.com/${cfg.tenantId}/oauth2/v2.0/token`,
48	    {
49	      method: 'POST',
50	      headers: { 'content-type': 'application/x-www-form-urlencoded' },
51	      body,
52	      signal: AbortSignal.timeout(10_000),
53	    },
54	  );
55	  if (!res.ok) {
56	    throw new Error(`Graph token failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
57	  }
58	  const data = (await res.json()) as { access_token: string; expires_in: number };
59	  cachedToken = {
60	    token: data.access_token,
61	    refreshAt: Date.now() + Math.max(60_000, data.expires_in * 1000 - 5 * 60 * 1000),
62	  };
63	  return cachedToken.token;
64	}
65	
66	interface SubscriptionConfig {
67	  notificationUrl: string;
68	  encryptionCertificate: string;
69	  encryptionCertificateId: string;
70	  clientState: string;
71	}
72	
73	function getSubscriptionConfigOrNull(): SubscriptionConfig | null {
74	  const notificationUrl = process.env.TEAMS_NOTIFICATION_URL;
75	  const encryptionCertificate = process.env.TEAMS_NOTIFICATION_PUBLIC_CERT;
76	  const encryptionCertificateId = process.env.TEAMS_NOTIFICATION_CERT_ID;
77	  const clientState = process.env.TEAMS_WEBHOOK_CLIENT_STATE;
78	  if (!notificationUrl || !encryptionCertificate || !encryptionCertificateId || !clientState) {
79	    return null;
80	  }
81	  return { notificationUrl, encryptionCertificate, encryptionCertificateId, clientState };
82	}
83	
84	interface GraphSub {
85	  id: string;
86	  resource: string;
87	  expirationDateTime: string;
88	  notificationUrl: string;
89	}
90	
91	export type EnsureResult = {
92	  action: 'created' | 'renewed' | 'ok' | 'skipped_no_config';
93	  subscriptionId?: string;
94	  expirationDateTime?: string;
95	  detail?: string;
96	};
97	
98	// Subscriptions for this resource max out near 1h. Renew to ~50m and re-up
99	// whenever the remaining lifetime drops under 20m (the cron runs every 30m).
100	const RENEW_MINUTES = 50;
101	const RENEW_IF_WITHIN_MS = 20 * 60 * 1000;
102	
103	/**
104	 * Ensure exactly one live ad-hoc transcript subscription exists pointing at our
105	 * webhook: renew it if it's near expiry, create it if it's missing. Safe to
106	 * call repeatedly (the renewal cron + webhook lifecycle events both call it).
107	 */
108	export async function ensureAdhocSubscription(): Promise<EnsureResult> {
109	  const cfg = getConfigOrNull();
110	  const subCfg = getSubscriptionConfigOrNull();
111	  if (!cfg || !subCfg) {
112	    return {
113	      action: 'skipped_no_config',
114	      detail: 'Azure creds or TEAMS_* subscription env not set in the worker environment',
115	    };
116	  }
117	  const token = await getToken(cfg);
118	  const authJson = { Authorization: `Bearer ${token}`, 'content-type': 'application/json' };
119	
120	  const listRes = await fetch(`${GRAPH_BETA}/subscriptions`, {
121	    headers: { Authorization: `Bearer ${token}` },
122	    signal: AbortSignal.timeout(20_000),
123	  });
124	  if (!listRes.ok) {
125	    throw new Error(`list subscriptions failed (${listRes.status}): ${(await listRes.text()).slice(0, 300)}`);
126	  }
127	  const subs = ((await listRes.json()) as { value?: GraphSub[] }).value ?? [];
128	  const mine = subs.find(
129	    (s) => s.resource === ADHOC_RESOURCE && s.notificationUrl === subCfg.notificationUrl,
130	  );
131	
132	  const nextExpiry = () => new Date(Date.now() + RENEW_MINUTES * 60_000).toISOString();
133	
134	  if (mine) {
135	    if (Date.parse(mine.expirationDateTime) - Date.now() > RENEW_IF_WITHIN_MS) {
136	      return { action: 'ok', subscriptionId: mine.id, expirationDateTime: mine.expirationDateTime };
137	    }
138	    const res = await fetch(`${GRAPH_BETA}/subscriptions/${mine.id}`, {
139	      method: 'PATCH',
140	      headers: authJson,
141	      body: JSON.stringify({ expirationDateTime: nextExpiry() }),
142	      signal: AbortSignal.timeout(20_000),
143	    });
