// READ-ONLY Graph probe: confirm which getAllTranscripts endpoint returns
// Albert's recent scheduled-meeting transcripts. Mirrors diagnose-transcripts.ps1
// with a current date window. No writes. Delete after.
import { config as loadEnv } from 'dotenv';
import { resolve } from 'node:path';

loadEnv({ path: resolve(process.cwd(), '..', '..', '.env.local') });

const tenantId = process.env.AZURE_TENANT_ID;
const clientId = process.env.AZURE_GRAPH_CLIENT_ID;
const clientSecret = process.env.AZURE_GRAPH_CLIENT_SECRET;
if (!tenantId || !clientId || !clientSecret) throw new Error('missing AZURE_* env');

const body = new URLSearchParams({
  client_id: clientId, client_secret: clientSecret,
  scope: 'https://graph.microsoft.com/.default', grant_type: 'client_credentials',
});
const tok = await (await fetch(`https://login.microsoftonline.com/${tenantId}/oauth2/v2.0/token`, {
  method: 'POST', headers: { 'content-type': 'application/x-www-form-urlencoded' }, body,
})).json();
const H = { Authorization: `Bearer ${tok.access_token}` };

const u = await (await fetch('https://graph.microsoft.com/v1.0/users/Albert@popcre.com', { headers: H })).json();
const uid = u.id;
console.log('Organizer:', u.displayName, 'id=', uid);

const start = '2026-06-17T00:00:00Z';
const end = '2026-06-24T23:59:59Z';

async function tryUrl(label, url) {
  try {
    const res = await fetch(url, { headers: H });
