export async function getOnlineMeetingTranscripts(
  organizerId: string,
  sinceIso: string,
): Promise<BackfillTranscript[]> {
  const cfg = getConfigOrNull();
  if (!cfg) return [];
  const token = await getToken(cfg);
  const out: BackfillTranscript[] = [];
  let url: string | undefined =
    `${GRAPH_BETA}/communications/onlineMeetings/getAllTranscripts(meetingOrganizerUserId='${organizerId}',startDateTime=${sinceIso})`;
  while (url) {
    const res = await fetch(url, {
      headers: { Authorization: `Bearer ${token}` },
      signal: AbortSignal.timeout(20_000),
    });
    if (!res.ok) {
      // Per-organizer best-effort: skip users with no meetings / no access.
      if (res.status === 403 || res.status === 404) return out;
      throw new Error(`getAllTranscripts failed (${res.status}): ${(await res.text()).slice(0, 300)}`);
    }

