// READ-ONLY: confirm backfilled transcripts landed in prod (awaiting_approval).
import postgres from 'postgres';
const url = process.env.VERIFY_URL;
const sql = postgres(url, { max: 1, prepare: true });
try {
  const rt = await sql`
    SELECT approval_status, count(*)::int AS n, max(created_at) AS latest
    FROM raw_transcripts GROUP BY approval_status ORDER BY approval_status`;
  console.log('raw_transcripts:', rt.length ? rt.map((r)=>`${r.approval_status}=${r.n} (latest ${r.latest})`).join('; ') : '(none)');
  const msg = await sql`
    SELECT extraction_status, count(*)::int AS n
    FROM messages WHERE metadata_json->>'source' = 'teams_transcript'
    GROUP BY extraction_status ORDER BY extraction_status`;
  console.log('teams_transcript messages by status:', msg.length ? msg.map((r)=>`${r.extraction_status}=${r.n}`).join('; ') : '(none)');
  const ch = await sql`
    SELECT name, created_at FROM channels WHERE name LIKE 'Teams call %' ORDER BY created_at DESC LIMIT 5`;
  console.log('recent Teams-call channels:');
  for (const c of ch) console.log('  ', c.name, '|', c.created_at);
} finally { await sql.end({ timeout: 5 }); }

