// READ-ONLY: compare transcript state in both DBs to see where the worker writes.
import postgres from 'postgres';
const url = process.env.CHECK_URL;
const sql = postgres(url, { max: 1, prepare: true });
try {
  console.log('host:', new URL(url).host);
  const rt = await sql`SELECT count(*)::int AS n, max(created_at) AS latest FROM raw_transcripts`;
  console.log('  raw_transcripts:', rt[0].n, '| latest:', rt[0].latest ?? '(none)');
  const ch = await sql`SELECT count(*)::int AS n, max(created_at) AS latest FROM channels WHERE name LIKE 'Teams call %'`;
  console.log('  Teams-call channels:', ch[0].n, '| latest:', ch[0].latest ?? '(none)');
  const hasCol = await sql`SELECT 1 FROM information_schema.columns WHERE table_name='raw_transcripts' AND column_name='approval_status'`;
  console.log('  has approval_status column:', hasCol.length > 0);
  const enumHas = await sql`
    SELECT 1 FROM pg_enum e JOIN pg_type t ON t.oid=e.enumtypid
    WHERE t.typname='extraction_status' AND e.enumlabel='awaiting_approval'`;
  console.log('  enum has awaiting_approval:', enumHas.length > 0);
} finally { await sql.end({ timeout: 5 }); }

