    FROM messages WHERE metadata_json->>'source'='teams_transcript'
    GROUP BY extraction_status ORDER BY extraction_status`;
  console.log('teams_transcript messages by status:', msg.map(r=>`${r.extraction_status}=${r.n}`).join('; ') || '(none)');
