// Deletes ONLY: orphan raw_transcripts with the long (>64 char) pre-fix ids,
// and empty Teams-call channels created today (0 messages). Real recovered
// transcripts (32-char hashed ids, with messages) are untouched. Transactional.
import postgres from 'postgres';
const sql = postgres(process.env.VERIFY_URL, { max: 1, prepare: true });
try {
  const before = await sql`SELECT count(*)::int AS n FROM raw_transcripts`;
  console.log('raw_transcripts before:', before[0].n);

  const result = await sql.begin(async (tx) => {
    const delRt = await tx`DELETE FROM raw_transcripts WHERE length(transcript_id) > 64 RETURNING transcript_id`;
    const emptyChannels = tx`
      SELECT id FROM channels c
      WHERE c.name LIKE 'Teams call %' AND c.created_at::date = current_date
        AND NOT EXISTS (SELECT 1 FROM messages m WHERE m.channel_id = c.id)`;
    await tx`DELETE FROM channel_participants WHERE channel_id IN (${emptyChannels})`;
    const delCh = await tx`
      DELETE FROM channels c
      WHERE c.name LIKE 'Teams call %' AND c.created_at::date = current_date
        AND NOT EXISTS (SELECT 1 FROM messages m WHERE m.channel_id = c.id)
      RETURNING c.id`;
    return { rt: delRt.length, ch: delCh.length };
  });
  console.log(`deleted: ${result.rt} orphan raw_transcripts, ${result.ch} empty channels`);

  const after = await sql`
    SELECT rt.approval_status, length(rt.transcript_id) AS id_len,
