try {
  const result = await sql.begin(async (tx) => {
    const chans = (await tx`SELECT channel_id FROM raw_transcripts WHERE channel_id IS NOT NULL`).map(c=>c.channel_id);
    if (chans.length === 0) return { channels: 0, msgs: 0, rt: 0, gaps: 0, interventions: 0 };
    const msgIds = (await tx`SELECT id FROM messages WHERE channel_id IN ${sql(chans)}`).map(m=>m.id);
    // Byproducts created by lull-interjection seeing the (ingestion-time-stamped) transcript as live.
    const delIv = msgIds.length ? await tx`DELETE FROM oracle_interventions WHERE interjection_message_id IN ${sql(msgIds)} OR related_message_id IN ${sql(msgIds)} RETURNING id` : [];
    const delGap = msgIds.length ? await tx`DELETE FROM gaps WHERE asked_in_message_id IN ${sql(msgIds)} RETURNING id` : [];
    const delMsg = await tx`DELETE FROM messages WHERE channel_id IN ${sql(chans)} RETURNING id`;
    await tx`DELETE FROM channel_participants WHERE channel_id IN ${sql(chans)}`;
    const delRt = await tx`DELETE FROM raw_transcripts WHERE channel_id IN ${sql(chans)} RETURNING transcript_id`;
    const delCh = await tx`DELETE FROM channels WHERE id IN ${sql(chans)} RETURNING id`;
    return { channels: delCh.length, msgs: delMsg.length, rt: delRt.length, gaps: delGap.length, interventions: delIv.length };
  });
  console.log(`deleted: ${result.rt} raw_transcripts, ${result.channels} channels, ${result.msgs} messages, ${result.gaps} gaps, ${result.interventions} interventions`);
