  const employeeId = c.speaker ? (resolvedBySpeaker.get(c.speaker) ?? null) : null;
  if (employeeId) participantIds.add(employeeId);
  return {
    channelId: channel.id,
    employeeId,
    role: 'user' as const,
    content: c.text,
