      source: 'teams_transcript',
      transcriptId,
      meetingId: payload.meetingId ?? null,
      callId: payload.callId ?? null,
      speaker: c.speaker,
      offsetMs: c.offsetMs,
      resolvedEmployeeId: employeeId,
    },
  };
});

