try {
  const rows = await sql`
    SELECT status, organizer_name, organizer_id, meeting_time, discovered_via,
           left(transcript_id, 20) AS tid
    FROM meeting_transcripts ORDER BY meeting_time DESC NULLS LAST`;
  console.log(`meeting_transcripts (${rows.length}):`);
  for (const r of rows) console.log(`  [${r.status}] via=${r.discovered_via} organizer=${r.organizer_name ?? r.organizer_id ?? '—'} time=${r.meeting_time ?? '—'} tid=${r.tid}…`);
  const tmsg = await sql`SELECT count(*)::int AS n FROM messages WHERE metadata_json->>'source'='teams_transcript'`;
  console.log(`\nteams_transcript messages (should still be 95 = Jun 4 only, no new ingest): ${tmsg[0].n}`);
} finally { await sql.end({ timeout: 5 }); }

